  1	import { useCallback, useMemo, useState } from 'react';
  2	
  3	import { RESTApi } from '@API/REST.api';
  4	import { I18nNamespace } from '@config/config';
  5	import SkTable from '@core/components/SkTable';
  6	import StatusCell from '@core/components/StatusCell';
  7	import { useWatchedSkupperResource } from '@hooks/useSkupperWatchResource';
  8	import { Listener } from '@interfaces/REST.interfaces';
  9	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 10	import {
 11	  Button,
 12	  Modal,
 13	  ModalVariant,
 14	  Alert,
 15	  Stack,
 16	  StackItem,
 17	  AlertActionCloseButton,
 18	  DrawerPanelContent,
 19	  DrawerHead,
 20	  DrawerActions,
 21	  DrawerCloseButton,
 22	  Drawer,
 23	  DrawerContent,
 24	  DrawerContentBody,
 25	  DrawerPanelBody,
 26	  Card,
 27	  CardBody
 28	} from '@patternfly/react-core';
 29	import { useMutation } from '@tanstack/react-query';
 30	import { useTranslation } from 'react-i18next';
 31	
 32	import ListenerDetails from './ListenerDetails';
 33	import LoadingPage from '../../../core/components/Loading';
 34	import ListenerForm from '../../components/forms/ListenerForm';
 35	
 36	const Listeners = function () {
 37	  const { t } = useTranslation(I18nNamespace);
 38	
 39	  const [isOpen, setIsOpen] = useState<boolean>();
 40	  const [showAlert, setShowAlert] = useState<string>(sessionStorage.getItem('showListenerAlert') || 'show');
 41	  const [nameSelected, setNameSelected] = useState<string | undefined>();
 42	
 43	  const { data: listeners, loaded } = useWatchedSkupperResource({ kind: 'Listener' });
 44	
 45	  const mutationDelete = useMutation({
 46	    mutationFn: (name: string) => RESTApi.deleteListener(name),
 47	    onSuccess: () => handleCloseDetails()
 48	  });
 49	
 50	  const handleDelete = useCallback(
 51	    (name: string) => {
 52	      mutationDelete.mutate(name);
 53	    },
 54	    [mutationDelete]
 55	  );
 56	
 57	  const handleModalClose = useCallback(() => {
 58	    setIsOpen(undefined);
 59	  }, []);
 60	
 61	  const handleOpenDetails = useCallback((name: string) => {
 62	    setNameSelected(name);
 63	  }, []);
 64	
 65	  const handleCloseDetails = useCallback(() => {
 66	    setNameSelected(undefined);
 67	  }, []);
 68	
 69	  const handleCloseAlert = useCallback(() => {
 70	    setShowAlert('hide');
 71	    sessionStorage.setItem('showListenerAlert', 'hide');
 72	  }, []);
 73	
 74	  const Columns: SKColumn<Listener>[] = [
 75	    {
 76	      name: t('Name'),
 77	      prop: 'name',
 78	      customCellName: 'linkCell'
 79	    },
 80	    {
 81	      name: t('Status'),
 82	      prop: 'status',
 83	      customCellName: 'StatusCell'
 84	    },
 85	    {
 86	      name: t('Message'),
 87	      prop: 'statusMessage'
 88	    },
 89	    {
 90	      name: t('Routing key'),
 91	      prop: 'routingKey'
 92	    },
 93	    {
 94	      name: t('Service name'),
 95	      prop: 'serviceName'
 96	    },
 97	    {
 98	      name: t('Port'),
 99	      prop: 'port'
100	    },
101	    {
102	      name: t('Has connectors'),
103	      prop: 'connected',
104	      customCellName: 'connectedCell'
105	    },
106	    {
107	      name: '',
108	      customCellName: 'actions',
109	      modifier: 'fitContent'
110	    }
111	  ];
112	
113	  const customCells = useMemo(
114	    () => ({
115	      linkCell: ({ data }: SKComponentProps<Listener>) => (
116	        <Button variant="link" onClick={handleOpenDetails.bind(null, data.name)}>
117	          {data.name}
118	        </Button>
119	      ),
120	      StatusCell,
121	      connectedCell: ({ data }: SKComponentProps<Listener>) => `${data.connected}`,
122	      actions: ({ data }: SKComponentProps<Listener>) => (
123	        <Button onClick={handleDelete.bind(null, data.name)} variant="link">
124	          {t('Delete')}
125	        </Button>
126	      )
127	    }),
128	    [handleDelete, handleOpenDetails, t]
129	  );
130	
131	  const panelContent = (
132	    <DrawerPanelContent isResizable minSize="30%" data-testid="drawer-panel">
133	      <DrawerHead>
134	        <DrawerActions>
135	          <DrawerCloseButton onClick={handleCloseDetails} />
136	        </DrawerActions>
137	      </DrawerHead>
138	      <DrawerPanelBody data-testid="listener-details-panel">
139	        {nameSelected && <ListenerDetails name={nameSelected} onUpdate={handleModalClose} />}
140	      </DrawerPanelBody>
141	    </DrawerPanelContent>
142	  );
143	
144	  if (!loaded) {
145	    return <LoadingPage />;
146	  }
147	
148	  return (
149	    <Card isPlain isFullHeight>
150	      <CardBody>
151	        <Stack hasGutter>
152	          <StackItem>
153	            {showAlert === 'show' && (
154	              <Alert
155	                hidden={true}
156	                variant="info"
157	                isInline
158	                actionClose={<AlertActionCloseButton data-testid="listener-alert-close" onClose={handleCloseAlert} />}
159	                title={t(
160	                  'A listener is a local connection endpoint that is associated with remote servers. Listeners expose a host and port for accepting connections. Listeners use a routing key to forward connection data to remote connectors.'
161	                )}
162	              />
163	            )}
164	          </StackItem>
165	
166	          <StackItem isFilled>
167	            <Button onClick={() => setIsOpen(true)}>{t('Create a listener')}</Button>{' '}
168	            <Drawer isExpanded={!!nameSelected} isInline>
169	              <DrawerContent panelContent={panelContent}>
170	                <DrawerContentBody>
171	                  <SkTable
172	                    columns={Columns}
173	                    rows={listeners || []}
174	                    alwaysShowPagination={false}
175	                    customCells={customCells}
176	                    isPlain
177	                  />
178	                </DrawerContentBody>
179	              </DrawerContent>
180	            </Drawer>
181	          </StackItem>
182	        </Stack>
183	
184	        <Modal
185	          hasNoBodyWrapper
186	          isOpen={!!isOpen}
187	          variant={ModalVariant.medium}
188	          aria-label="Form create listener"
189	          showClose={false}
190	        >
191	          <ListenerForm onSubmit={handleModalClose} onCancel={handleModalClose} title={t('Create a listener')} />
192	        </Modal>
193	      </CardBody>
194	    </Card>
195	  );
196	};
197	
198	export default Listeners;

